(window.webpackJsonp=window.webpackJsonp||[]).push([[250],{877:function(n,e){n.exports="\x3c!-- \ntitle: ADB\nsort: \n--\x3e \n# ADB命令入门\n\n## 操作\n\n```powershell\n# 安装应用\nadb install *.apk\n# 屏幕截图\nadb shell screencap /sdcard/screen.png\n# 文件传送至电脑\nadb pull /sdcard/screen.png d:\\test\\\n# 点击屏幕 100,100像素\nadb shell input tap 100 100\n# 滑动 开始坐标 结束坐标 延迟时间\nadb shell input swipe 500 1500 500 500 500\n# 设备信息 -s \nadb devices\n```\n\n## 模拟按键\n\n```powershell\nadb shell input keyevent <keycode>\n```\n\n| keycode | 含义                           |\n| :------ | :----------------------------- |\n| 3       | HOME 键                        |\n| 4       | 返回键                         |\n| 5       | 打开拨号应用                   |\n| 6       | 挂断电话                       |\n| 24      | 增加音量                       |\n| 25      | 降低音量                       |\n| 26      | 电源键                         |\n| 27      | 拍照（需要在相机应用里）       |\n| 64      | 打开浏览器                     |\n| 82      | 菜单键                         |\n| 85      | 播放/暂停                      |\n| 86      | 停止播放                       |\n| 87      | 播放下一首                     |\n| 88      | 播放上一首                     |\n| 122     | 移动光标到行首或列表顶部       |\n| 123     | 移动光标到行末或列表底部       |\n| 126     | 恢复播放                       |\n| 127     | 暂停播放                       |\n| 164     | 静音                           |\n| 176     | 打开系统设置                   |\n| 187     | 切换应用                       |\n| 207     | 打开联系人                     |\n| 208     | 打开日历                       |\n| 209     | 打开音乐                       |\n| 210     | 打开计算器                     |\n| 220     | 降低屏幕亮度                   |\n| 221     | 提高屏幕亮度                   |\n| 223     | 系统休眠                       |\n| 224     | 点亮屏幕                       |\n| 231     | 打开语音助手                   |\n| 276     | 如果没有 wakelock 则让系统休眠 |"}}]);